 1	import * as _ from 'lodash';
 2	import * as React from 'react';
 3	import {
 4	  Dropdown,
 5	  DropdownItem,
 6	  MenuToggleElement,
 7	  MenuToggle,
 8	  DropdownList,
 9	} from '@patternfly/react-core';
10	import { IntervalOptions } from './utils';
11	import { formatPrometheusDuration, parsePrometheusDuration } from './dateTime';
12	
13	import './PipelinesOverview.scss';
14	
15	const OFF_KEY = 'OFF_KEY';
16	
17	type Props = {
18	  interval: number;
19	  setInterval: (v: number) => void;
20	  id?: string;
21	};
22	
23	const IntervalDropdown: React.FC<Props> = ({ id, interval, setInterval }) => {
24	  const [isOpen, setValue] = React.useState(false);
25	  const toggleIsOpen = React.useCallback(() => setValue((v) => !v), []);
26	  const setClosed = React.useCallback(() => setValue(false), []);
27	  const intervalOptions = IntervalOptions();
28	
29	  const onChange = React.useCallback(
30	    (v: string) =>
31	      setInterval(v === OFF_KEY ? null : parsePrometheusDuration(v)),
32	    [setInterval],
33	  );
34	
35	  const selectedKey =
36	    interval === null ? OFF_KEY : formatPrometheusDuration(interval);
37	
38	  return (
39	    <Dropdown
40	      isOpen={isOpen}
41	      onSelect={setClosed}
42	      onOpenChange={(isOpen: boolean) => setValue(isOpen)}
43	      toggle={(toggleRef: React.Ref<MenuToggleElement>) => (
44	        <MenuToggle
45	          ref={toggleRef}
46	          onClick={toggleIsOpen}
47	          className="pipeline-overview__dropdown-button"
48	          id={`${id}-dropdown`}
49	        >
50	          {intervalOptions[selectedKey]}
51	        </MenuToggle>
52	      )}
53	      className="pipeline-overview__variable-dropdown"
54	    >
55	      <DropdownList>
56	        {_.map(intervalOptions, (name, key) => (
57	          <DropdownItem
58	            component="button"
59	            key={key}
60	            onClick={() => onChange(key)}
61	          >
62	            {name}
63	          </DropdownItem>
64	        ))}
65	      </DropdownList>
66	    </Dropdown>
67	  );
68	};
69	
70	export default IntervalDropdown;

